    /**
     * @abstract 生成随机姓名
     * @return string
     */
    public function getName($_sys_country){
        date_default_timezone_set("Asia/Shanghai");

        Redis::select(1);

        $_userIndex = Redis::get("rand_user_index");

        if(!$_userIndex){
            $_userIndex = 1;
        }

        Redis::INCR("rand_user_index");

        $_rand_name = "runball_".$_userIndex;


        return $_rand_name;
    }

